import React, { useEffect, useState } from "react";
import { LineChart, Line, XAxis, YAxis, Tooltip, CartesianGrid } from "recharts";

const MapComponent = () => {
  const [buses, setBuses] = useState([]);
  const [showChart, setShowChart] = useState(false);
  const [trendData, setTrendData] = useState([]);
  const [zoom, setZoom] = useState(10);

  // Fetch buses every 2 minutes
  useEffect(() => {
    const fetchBuses = async () => {
      try {
        const res = await fetch("http://localhost:8000/buses");
        const data = await res.json();
        setBuses(data);

        // Update trend data
        const normalCount = data.filter(b => b.status === "normal").length;
        const ghostCount = data.filter(b => b.status === "ghost").length;
        const anomalyCount = data.filter(b => b.status === "anomaly").length;

        setTrendData(prev => [
          ...prev,
          {
            time: new Date().toLocaleTimeString(),
            normal: normalCount,
            ghost: ghostCount,
            anomaly: anomalyCount
          }
        ].slice(-20)); // keep last 20 points
      } catch (err) {
        console.error("Error fetching buses:", err);
      }
    };

    fetchBuses();
    const interval = setInterval(fetchBuses, 120000); // 2 min
    return () => clearInterval(interval);
  }, []);

  // Counts
  const normalCount = buses.filter(b => b.status === "normal").length;
  const ghostCount = buses.filter(b => b.status === "ghost").length;
  const anomalyCount = buses.filter(b => b.status === "anomaly").length;

  return (
    <div style={{ position: "relative", width: "100vw", height: "100vh", background: "#f8f8f8" }}>
      {/* Simple 2D Map */}
      <div style={{
        position: "absolute",
        top: 0,
        left: 0,
        width: "100%",
        height: "100%",
        backgroundColor: "#ffffff",
        overflow: "hidden"
      }}>
        {buses.map((bus, index) => {
          // Map lat/lon to position (simplified, for demo only)
          const x = ((bus.lon + 74.1) / 0.2) * window.innerWidth;  // adjust scale
          const y = ((40.9 - bus.lat) / 0.2) * window.innerHeight;

          const color = bus.status === "normal" ? "green" : bus.status === "ghost" ? "red" : "orange";

          return (
            <div
              key={`${bus.id}_${bus.timestamp}_${index}`} // unique key
              style={{
                position: "absolute",
                left: x,
                top: y,
                width: "12px",
                height: "12px",
                borderRadius: "50%",
                backgroundColor: color,
                border: "2px solid white",
                transform: "translate(-50%, -50%)"
              }}
            />
          );
        })}
      </div>

      {/* Zoom and Chart Buttons */}
      <div style={{ position: "absolute", top: 10, left: 10, display: "flex", flexDirection: "column", gap: "8px" }}>
        <button onClick={() => setZoom(prev => prev + 1)}>Zoom In</button>
        <button onClick={() => setZoom(prev => Math.max(prev - 1, 1))}>Zoom Out</button>
        <button onClick={() => setShowChart(prev => !prev)}>
          {showChart ? "Hide Chart" : "Show Chart"}
        </button>
      </div>

      {/* Counters */}
      <div style={{
        position: "absolute",
        bottom: 10,
        left: 10,
        background: "rgba(255,255,255,0.9)",
        padding: "10px",
        borderRadius: "8px"
      }}>
        <div>Normal: {normalCount}</div>
        <div>Ghost: {ghostCount}</div>
        <div>Anomaly: {anomalyCount}</div>
      </div>

      {/* Trend Chart */}
      {showChart && (
        <div style={{
          position: "absolute",
          bottom: 10,
          right: 10,
          background: "rgba(255,255,255,0.95)",
          padding: "10px",
          borderRadius: "8px"
        }}>
          <LineChart width={500} height={250} data={trendData}>
            <XAxis dataKey="time" />
            <YAxis />
            <Tooltip />
            <CartesianGrid stroke="#f5f5f5" />
            <Line type="monotone" dataKey="normal" stroke="green" />
            <Line type="monotone" dataKey="ghost" stroke="red" />
            <Line type="monotone" dataKey="anomaly" stroke="orange" />
          </LineChart>
        </div>
      )}
    </div>
  );
};

export default MapComponent;
